export function render(value, onChange, api, options = {}) {
  const container = document.createElement('div');
  container.style.cssText = 'display: flex; gap: 8px; align-items: center;';

  // Display area for current selection
  const displayArea = document.createElement('div');
  displayArea.style.cssText = 'flex: 1; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px; background: #f9f9f9; min-height: 36px; display: flex; align-items: center;';

  const updateDisplay = async () => {
    if (!value || value === '') {
      displayArea.textContent = '(no item selected)';
      displayArea.style.color = '#999';
      displayArea.style.fontStyle = 'italic';
    } else {
      displayArea.textContent = 'Loading...';
      displayArea.style.color = '#666';
      displayArea.style.fontStyle = 'italic';

      try {
        const item = await api.get(value);
        displayArea.textContent = item.name || item.content?.title || item.id.substring(0, 8) + '...';
        displayArea.style.color = '#333';
        displayArea.style.fontStyle = 'normal';
      } catch (e) {
        displayArea.textContent = '(invalid reference: ' + value.substring(0, 8) + '...)';
        displayArea.style.color = '#c00';
        displayArea.style.fontStyle = 'italic';
      }
    }
  };

  updateDisplay();
  container.appendChild(displayArea);

  if (!options.readonly) {
    // Select button
    const selectBtn = document.createElement('button');
    selectBtn.textContent = 'Select...';
    selectBtn.style.cssText = 'padding: 8px 16px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px; font-size: 14px;';
    selectBtn.onclick = () => openModal();
    container.appendChild(selectBtn);

    // Clear button (only show if there's a value)
    const clearBtn = document.createElement('button');
    clearBtn.textContent = '×';
    clearBtn.title = 'Clear selection';
    clearBtn.style.cssText = 'padding: 8px 12px; cursor: pointer; background: #dc3545; color: white; border: none; border-radius: 4px; font-size: 16px; font-weight: bold;';
    clearBtn.onclick = () => {
      onChange('');
      value = '';
      updateDisplay();
    };
    if (value && value !== '') {
      container.appendChild(clearBtn);
    }

    // Modal/overlay
    const openModal = async () => {
      const overlay = document.createElement('div');
      overlay.style.cssText = `
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background: rgba(0, 0, 0, 0.5);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 10000;
      `;

      const modalBox = document.createElement('div');
      modalBox.style.cssText = `
        background: white;
        padding: 24px;
        border-radius: 8px;
        width: 600px;
        max-height: 80vh;
        overflow: auto;
        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
      `;

      // Modal header
      const modalHeader = document.createElement('div');
      modalHeader.style.cssText = 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; padding-bottom: 12px; border-bottom: 2px solid #e0e0e0;';

      const modalTitle = document.createElement('h3');
      modalTitle.textContent = options.modalTitle || 'Select Item';
      modalTitle.style.cssText = 'margin: 0; font-size: 18px;';
      modalHeader.appendChild(modalTitle);

      const closeBtn = document.createElement('button');
      closeBtn.textContent = '×';
      closeBtn.style.cssText = 'padding: 4px 10px; cursor: pointer; background: transparent; border: none; font-size: 24px; color: #666; line-height: 1;';
      closeBtn.onclick = () => document.body.removeChild(overlay);
      modalHeader.appendChild(closeBtn);

      modalBox.appendChild(modalHeader);

      // Search UI container
      const searchContainer = document.createElement('div');
      modalBox.appendChild(searchContainer);

      overlay.appendChild(modalBox);
      document.body.appendChild(overlay);

      // Load search library and create search UI
      const searchLib = await api.require('item_search_lib');
      searchLib.createSearchUI(
        searchContainer,
        (selectedItem) => {
          onChange(selectedItem.id);
          value = selectedItem.id;
          updateDisplay();
          document.body.removeChild(overlay);
        },
        api,
        {
          placeholder: options.searchPlaceholder || 'Search for items...',
          targetContainer: options.targetContainer || null,
          autoFocus: true
        }
      );

      // Click backdrop to close
      overlay.onclick = (e) => {
        if (e.target === overlay) {
          document.body.removeChild(overlay);
        }
      };

      // Stop propagation on modal box to prevent backdrop close
      modalBox.onclick = (e) => {
        e.stopPropagation();
      };
    };
  }

  return container;
}

export async function render(item, api) {
  // Load standard context menu CSS
  const cssLoader = await api.require('css_loader_lib');
  await cssLoader.loadCSS('context_menu_css', api);

  // The viewport item stores rootId in children[0] (as an object with id)
  // and rootRendererId in content.rootRendererId
  const rootSpec = item.children?.[0];
  const rootId = rootSpec?.id || rootSpec;
  const rootRendererId = rootSpec?.renderer || null;

  // Create main container
  const container = api.createElement('div', {
    class: 'viewport-container',
    style: 'display: flex; flex-direction: column; height: 100%; position: relative;'
  }, []);

  // Create navigation bar
  const navBar = api.createElement('div', {
    class: 'nav-bar',
    style: 'display: flex; align-items: center; padding: 8px 15px; background: #f5f5f5; border-bottom: 1px solid #ddd; gap: 10px;'
  }, []);

  // Back button
  const backBtn = api.createElement('button', {
    style: 'padding: 4px 12px; cursor: pointer;',
    onclick: () => window.history.back()
  }, ['← Back']);
  navBar.appendChild(backBtn);

  // All Items button
  const allItemsBtn = api.createElement('button', {
    style: 'padding: 4px 12px; cursor: pointer;',
    onclick: async () => await api.showItemList()
  }, ['All Items']);
  navBar.appendChild(allItemsBtn);

  // New Item button
  if (rootId) {
    const newItemBtn = api.createElement('button', {
      style: 'padding: 4px 12px; cursor: pointer; background: #4a90e2; color: white; border: none; border-radius: 3px;',
      onclick: async () => {
        const CONTAINER_TYPE = '5c3f2631-cd4d-403a-be9c-e3a3c5ebdce9';

        // Helper: Show type picker modal
        const showTypePicker = () => {
          return new Promise(async (resolve) => {
            // Get all type definitions
            const allItems = await api.getAll();
            const types = allItems.filter(i => i.type === api.IDS.TYPE_DEFINITION);

            // Create modal
            const overlay = api.createElement('div', {
              style: `
                position: fixed;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                background: rgba(0, 0, 0, 0.5);
                display: flex;
                align-items: center;
                justify-content: center;
                z-index: 10000;
              `
            }, []);

            const modal = api.createElement('div', {
              style: `
                background: white;
                border-radius: 8px;
                padding: 24px;
                max-width: 500px;
                max-height: 600px;
                overflow: auto;
              `
            }, []);

            const title = api.createElement('h3', { style: 'margin-top: 0;' }, ['Select Item Type']);
            modal.appendChild(title);

            const typeList = api.createElement('div', {
              style: 'display: flex; flex-direction: column; gap: 8px;'
            }, []);

            for (const type of types) {
              const typeBtn = api.createElement('button', {
                style: `
                  padding: 12px;
                  text-align: left;
                  border: 1px solid #ddd;
                  border-radius: 4px;
                  background: white;
                  cursor: pointer;
                `,
                onclick: () => {
                  document.body.removeChild(overlay);
                  resolve(type.id);
                }
              }, []);

              const typeName = api.createElement('div', {
                style: 'font-weight: bold;'
              }, [type.name || type.id.slice(0, 8)]);
              typeBtn.appendChild(typeName);

              if (type.content?.description) {
                const typeDesc = api.createElement('div', {
                  style: 'font-size: 12px; color: #666; margin-top: 4px;'
                }, [type.content.description]);
                typeBtn.appendChild(typeDesc);
              }

              typeList.appendChild(typeBtn);
            }

            modal.appendChild(typeList);

            const cancelBtn = api.createElement('button', {
              style: 'margin-top: 16px; padding: 8px 16px; cursor: pointer;',
              onclick: () => {
                document.body.removeChild(overlay);
                resolve(null);
              }
            }, ['Cancel']);
            modal.appendChild(cancelBtn);

            overlay.appendChild(modal);

            // Close on overlay click
            overlay.onclick = (e) => {
              if (e.target === overlay) {
                document.body.removeChild(overlay);
                resolve(null);
              }
            };

            document.body.appendChild(overlay);
          });
        };

        // Check if root is a container
        const rootItem = await api.get(rootId);
        const isContainer = await api.typeChainIncludes(rootItem.type, CONTAINER_TYPE);

        // Show type picker
        const selectedType = await showTypePicker();
        if (!selectedType) return;

        // Create new item
        const newItem = {
          id: crypto.randomUUID(),
          type: selectedType,
          created: Date.now(),
          modified: Date.now(),
          children: [],
          content: {}
        };

        await api.set(newItem);

        if (isContainer) {
          // Add to container with default placement
          const updatedRoot = await api.get(rootId);
          const children = updatedRoot.children || [];

          // Find max z-index for new item
          const maxZ = children.length > 0
            ? Math.max(...children.map(c => c.z || 1000))
            : 999;

          children.push({
            id: newItem.id,
            x: 0,
            y: 0,
            width: 400,
            height: 300,
            z: maxZ + 1
          });

          updatedRoot.children = children;
          updatedRoot.modified = Date.now();
          await api.set(updatedRoot);

          // Refresh view to show new item
          await api.navigate(rootId);

          // Open item in edit mode
          await api.editItem(newItem.id);
        } else {
          // Open in editor with custom save buttons
          const overlay = api.createElement('div', {
            style: `
              position: fixed;
              top: 0;
              left: 0;
              right: 0;
              bottom: 0;
              background: rgba(0, 0, 0, 0.5);
              display: flex;
              align-items: center;
              justify-content: center;
              z-index: 10000;
            `
          }, []);

          const modal = api.createElement('div', {
            style: `
              background: white;
              border-radius: 8px;
              padding: 24px;
              max-width: 600px;
              width: 90%;
              max-height: 80%;
              display: flex;
              flex-direction: column;
            `
          }, []);

          const header = api.createElement('div', {
            style: 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px;'
          }, []);

          const title = api.createElement('h3', { style: 'margin: 0;' }, ['Edit New Item']);
          const closeBtn = api.createElement('button', {
            style: 'padding: 4px 8px; cursor: pointer;',
            onclick: async () => {
              // Delete unsaved item
              await api.delete(newItem.id);
              document.body.removeChild(overlay);
            }
          }, ['×']);

          header.appendChild(title);
          header.appendChild(closeBtn);
          modal.appendChild(header);

          // JSON editor
          const textarea = api.createElement('textarea', {
            style: `
              flex: 1;
              font-family: monospace;
              padding: 8px;
              border: 1px solid #ddd;
              border-radius: 4px;
              min-height: 300px;
            `
          }, []);
          textarea.value = JSON.stringify(newItem, null, 2);
          modal.appendChild(textarea);

          // Button container
          const buttonContainer = api.createElement('div', {
            style: 'display: flex; gap: 8px; margin-top: 16px;'
          }, []);

          const saveAndCloseBtn = api.createElement('button', {
            style: 'padding: 8px 16px; cursor: pointer; background: #4a90e2; color: white; border: none; border-radius: 3px;',
            onclick: async () => {
              try {
                const updated = JSON.parse(textarea.value);
                updated.modified = Date.now();
                await api.set(updated);
                document.body.removeChild(overlay);
                // Refresh current view
                await api.navigate(rootId);
              } catch (e) {
                alert('Invalid JSON: ' + e.message);
              }
            }
          }, ['Save and Close']);

          const saveAndViewBtn = api.createElement('button', {
            style: 'padding: 8px 16px; cursor: pointer; background: #27ae60; color: white; border: none; border-radius: 3px;',
            onclick: async () => {
              try {
                const updated = JSON.parse(textarea.value);
                updated.modified = Date.now();
                await api.set(updated);
                document.body.removeChild(overlay);
                // Navigate to new item as root
                await api.navigate(updated.id);
              } catch (e) {
                alert('Invalid JSON: ' + e.message);
              }
            }
          }, ['Save and View as Root']);

          buttonContainer.appendChild(saveAndCloseBtn);
          buttonContainer.appendChild(saveAndViewBtn);
          modal.appendChild(buttonContainer);

          overlay.appendChild(modal);
          document.body.appendChild(overlay);
        }
      }
    }, ['+ New Item']);
    navBar.appendChild(newItemBtn);
  }

  // Current item info
  if (rootId) {
    const rootItem = await api.get(rootId);
    const itemName = rootItem?.content?.title || rootItem?.name || rootId.slice(0, 8);
    const itemInfo = api.createElement('span', {
      style: 'margin-left: 10px; color: #666;'
    }, ['Viewing: ' + itemName]);
    navBar.appendChild(itemInfo);
  }

  container.appendChild(navBar);

  // If no root, show empty state
  if (!rootId) {
    const empty = api.createElement('div', {
      style: 'padding: 40px; text-align: center; color: #666;'
    }, ['No item selected. Use the REPL to navigate: api.navigate(itemId)']);
    container.appendChild(empty);
    return container;
  }

  // Render the root item
  let rootNode;
  try {
    rootNode = await api.renderItem(rootId, rootRendererId);
  } catch (error) {
    rootNode = api.createElement('div', {
      style: 'padding: 20px; color: #c00; background: #fff0f0; border: 1px solid #fcc; border-radius: 4px;'
    }, ['Error rendering item: ' + error.message]);
  }

  // Wrap root in a content area with data-item-id for selection
  const contentArea = api.createElement('div', {
    'data-item-id': rootId,
    class: 'viewport-content',
    style: 'flex: 1; overflow: auto; display: flex; flex-direction: column; min-height: 0;'
  }, [rootNode]);

  container.appendChild(contentArea);

  // Create context menu element (hidden by default)
  const contextMenu = api.createElement('div', {
    id: 'context-menu',
    class: 'context-menu',
    style: 'display: none;'
  }, []);
  container.appendChild(contextMenu);

  // Track selected item
  let selectedItemId = null;
  let selectedParentId = null;

  // Helper: update selection visual
  const updateSelectionVisual = () => {
    container.querySelectorAll('[data-item-id].item-selected').forEach(el => {
      el.classList.remove('item-selected');
    });
    if (selectedItemId) {
      const el = container.querySelector('[data-item-id="' + selectedItemId + '"]');
      if (el) el.classList.add('item-selected');
    }
  };

  // Helper: select item
  const selectItem = (itemId, itemElement) => {
    selectedItemId = itemId;
    selectedParentId = itemElement?.getAttribute('data-parent-id') || null;
    // Update viewport state
    api.viewport.select(itemId, selectedParentId);
    updateSelectionVisual();
  };

  // Helper: clear selection
  const clearSelection = () => {
    selectedItemId = null;
    selectedParentId = null;
    api.viewport.clearSelection();
    updateSelectionVisual();
  };

  // Helper: hide context menu
  const hideContextMenu = () => {
    contextMenu.style.display = 'none';
    contextMenu.innerHTML = '';
  };

  // Helper: show context menu
  const showContextMenu = async (x, y, itemId) => {
    const menuItem = await api.get(itemId);
    contextMenu.innerHTML = '';

    // "Display As..." submenu
    const displayAsItem = api.createElement('div', {
      class: 'context-menu-item context-menu-submenu'
    }, ['Display As...']);

    const displayAsSubmenu = api.createElement('div', {
      class: 'context-menu-submenu-items'
    }, []);

    // Get available renderers
    const renderers = await api.getRenderers(menuItem.type);

    // Get current renderer override
    let currentRendererId = null;
    if (selectedParentId) {
      const parent = await api.get(selectedParentId);
      const childSpec = parent.children?.find(c => c.id === itemId);
      currentRendererId = childSpec?.renderer || null;
    }

    if (renderers.length === 0) {
      const noRenderers = api.createElement('div', {
        class: 'context-menu-item disabled'
      }, ['(No renderers available)']);
      displayAsSubmenu.appendChild(noRenderers);
    } else {
      // Default option
      const defaultOption = api.createElement('div', {
        class: 'context-menu-item' + (currentRendererId === null ? ' selected' : '')
      }, ['Default' + (currentRendererId === null ? ' ✓' : '')]);
      defaultOption.onclick = async () => {
        hideContextMenu();
        if (selectedParentId) {
          await api.setChildRenderer(selectedParentId, itemId, null);
          await api.navigate(api.viewport.getRoot());
        }
      };
      displayAsSubmenu.appendChild(defaultOption);

      // Separator
      const sep = api.createElement('div', { class: 'context-menu-separator' }, []);
      displayAsSubmenu.appendChild(sep);

      // Each renderer
      for (const { renderer, forType, inherited } of renderers) {
        const isActive = currentRendererId === renderer.id;
        const rendererOption = api.createElement('div', {
          class: 'context-menu-item' + (isActive ? ' selected' : '')
        }, []);

        let label = renderer.name || renderer.id.slice(0, 8);
        if (inherited) {
          const typeItem = await api.get(forType);
          label += ' (from ' + (typeItem?.name || forType.slice(0, 8)) + ')';
        }
        if (isActive) label += ' ✓';
        rendererOption.textContent = label;

        rendererOption.onclick = async () => {
          hideContextMenu();
          if (selectedParentId) {
            await api.setChildRenderer(selectedParentId, itemId, renderer.id);
          } else {
            await api.viewport.setRootRenderer(renderer.id);
          }
          await api.navigate(api.viewport.getRoot());
        };
        displayAsSubmenu.appendChild(rendererOption);
      }
    }

    displayAsItem.appendChild(displayAsSubmenu);
    contextMenu.appendChild(displayAsItem);

    // "Edit With..." submenu
    const editWithItem = api.createElement('div', {
      class: 'context-menu-item context-menu-submenu'
    }, ['Edit With...']);

    const editWithSubmenu = api.createElement('div', {
      class: 'context-menu-submenu-items'
    }, []);

    // Get available editors
    const editors = await api.getEditors(menuItem.type);

    if (editors.length === 0) {
      const noEditors = api.createElement('div', {
        class: 'context-menu-item disabled'
      }, ['(No editors available)']);
      editWithSubmenu.appendChild(noEditors);
    } else {
      for (const { editor, forType, inherited } of editors) {
        const editorOption = api.createElement('div', {
          class: 'context-menu-item'
        }, []);

        let label = editor.name || editor.id.slice(0, 8);
        if (inherited) {
          const typeItem = await api.get(forType);
          label += ' (from ' + (typeItem?.name || forType.slice(0, 8)) + ')';
        }
        editorOption.textContent = label;

        editorOption.onclick = async () => {
          hideContextMenu();
          await api.editItem(itemId, editor.id);
        };
        editWithSubmenu.appendChild(editorOption);
      }
    }

    editWithItem.appendChild(editWithSubmenu);
    contextMenu.appendChild(editWithItem);

    // Separator
    const separator = api.createElement('div', { class: 'context-menu-separator' }, []);
    contextMenu.appendChild(separator);

    // Edit Raw JSON
    const editRawItem = api.createElement('div', { class: 'context-menu-item' }, ['Edit Raw JSON']);
    editRawItem.onclick = () => {
      hideContextMenu();
      api.editRaw(itemId);
    };
    contextMenu.appendChild(editRawItem);

    // Copy ID
    const copyIdItem = api.createElement('div', { class: 'context-menu-item' }, ['Copy ID']);
    copyIdItem.onclick = async () => {
      hideContextMenu();
      await navigator.clipboard.writeText(itemId);
      console.log('Copied ID:', itemId);
    };
    contextMenu.appendChild(copyIdItem);

    // Make Root
    const makeRootItem = api.createElement('div', { class: 'context-menu-item' }, ['Make Root']);
    makeRootItem.onclick = async () => {
      hideContextMenu();
      await api.navigate(itemId);
    };
    contextMenu.appendChild(makeRootItem);

    // Export as JSON
    const exportItem = api.createElement('div', { class: 'context-menu-item' }, ['Export as JSON']);
    exportItem.onclick = async () => {
      hideContextMenu();
      const itemData = await api.get(itemId);
      const json = JSON.stringify(itemData, null, 2);
      const blob = new Blob([json], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      const filename = (itemData.name || itemData.content?.title || itemId.slice(0, 8)) + '.json';
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      console.log('Exported item:', itemId);
    };
    contextMenu.appendChild(exportItem);

    // Dock submenu (only for items in containers)
    if (selectedParentId) {
      const dockItem = api.createElement('div', {
        class: 'context-menu-item context-menu-submenu'
      }, ['Dock']);

      const dockSubmenu = api.createElement('div', {
        class: 'context-menu-submenu-items'
      }, []);

      // Dock Left
      const dockLeftItem = api.createElement('div', {
        class: 'context-menu-item'
      }, ['Dock Left']);
      dockLeftItem.onclick = async (e) => {
        e.stopPropagation();
        hideContextMenu();
        const parent = await api.get(selectedParentId);
        const childSpec = parent.children?.find(c => c.id === itemId);
        if (!childSpec) return;

        const anyChild = document.querySelector('[data-parent-id="' + selectedParentId + '"]');
        const canvas = anyChild?.parentElement;
        const canvasHeight = canvas ? canvas.clientHeight : 600;
        const width = childSpec.width || 400;

        const updatedChildren = parent.children.map(c =>
          c.id === itemId
            ? { ...c, x: 0, y: 0, width: width, height: canvasHeight, minimized: false, maximized: false }
            : c
        );
        parent.children = updatedChildren;
        parent.modified = Date.now();
        await api.set(parent);
        await api.navigate(api.viewport.getRoot());
      };
      dockSubmenu.appendChild(dockLeftItem);

      // Dock Right
      const dockRightItem = api.createElement('div', {
        class: 'context-menu-item'
      }, ['Dock Right']);
      dockRightItem.onclick = async (e) => {
        e.stopPropagation();
        hideContextMenu();
        const parent = await api.get(selectedParentId);
        const childSpec = parent.children?.find(c => c.id === itemId);
        if (!childSpec) return;

        const anyChild = document.querySelector('[data-parent-id="' + selectedParentId + '"]');
        const canvas = anyChild?.parentElement;
        const canvasWidth = canvas ? canvas.clientWidth : 1000;
        const canvasHeight = canvas ? canvas.clientHeight : 600;
        const width = childSpec.width || 400;

        const updatedChildren = parent.children.map(c =>
          c.id === itemId
            ? { ...c, x: canvasWidth - width, y: 0, width: width, height: canvasHeight, minimized: false, maximized: false }
            : c
        );
        parent.children = updatedChildren;
        parent.modified = Date.now();
        await api.set(parent);
        await api.navigate(api.viewport.getRoot());
      };
      dockSubmenu.appendChild(dockRightItem);

      // Dock Top
      const dockTopItem = api.createElement('div', {
        class: 'context-menu-item'
      }, ['Dock Top']);
      dockTopItem.onclick = async (e) => {
        e.stopPropagation();
        hideContextMenu();
        const parent = await api.get(selectedParentId);
        const childSpec = parent.children?.find(c => c.id === itemId);
        if (!childSpec) return;

        const anyChild = document.querySelector('[data-parent-id="' + selectedParentId + '"]');
        const canvas = anyChild?.parentElement;
        const canvasWidth = canvas ? canvas.clientWidth : 1000;
        const height = childSpec.height || 300;

        const updatedChildren = parent.children.map(c =>
          c.id === itemId
            ? { ...c, x: 0, y: 0, width: canvasWidth, height: height, minimized: false, maximized: false }
            : c
        );
        parent.children = updatedChildren;
        parent.modified = Date.now();
        await api.set(parent);
        await api.navigate(api.viewport.getRoot());
      };
      dockSubmenu.appendChild(dockTopItem);

      // Dock Bottom
      const dockBottomItem = api.createElement('div', {
        class: 'context-menu-item'
      }, ['Dock Bottom']);
      dockBottomItem.onclick = async (e) => {
        e.stopPropagation();
        hideContextMenu();
        const parent = await api.get(selectedParentId);
        const childSpec = parent.children?.find(c => c.id === itemId);
        if (!childSpec) return;

        const anyChild = document.querySelector('[data-parent-id="' + selectedParentId + '"]');
        const canvas = anyChild?.parentElement;
        const canvasWidth = canvas ? canvas.clientWidth : 1000;
        const canvasHeight = canvas ? canvas.clientHeight : 600;
        const height = childSpec.height || 300;

        const updatedChildren = parent.children.map(c =>
          c.id === itemId
            ? { ...c, x: 0, y: canvasHeight - height, width: canvasWidth, height: height, minimized: false, maximized: false }
            : c
        );
        parent.children = updatedChildren;
        parent.modified = Date.now();
        await api.set(parent);
        await api.navigate(api.viewport.getRoot());
      };
      dockSubmenu.appendChild(dockBottomItem);

      dockItem.appendChild(dockSubmenu);
      contextMenu.appendChild(dockItem);
    }

    // Delete (with confirmation)
    const separator2 = api.createElement('div', { class: 'context-menu-separator' }, []);
    contextMenu.appendChild(separator2);

    const deleteItem = api.createElement('div', {
      class: 'context-menu-item',
      style: 'color: #d33;'
    }, ['Delete']);
    deleteItem.onclick = async () => {
      hideContextMenu();

      // Show confirmation dialog
      const itemData = await api.get(itemId);
      const itemLabel = itemData.name || itemData.content?.title || itemId.slice(0, 8);

      const overlay = api.createElement('div', {
        style: `
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.5);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 10000;
        `
      }, []);

      const modal = api.createElement('div', {
        style: `
          background: white;
          border-radius: 8px;
          padding: 24px;
          max-width: 400px;
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
        `
      }, []);

      const title = api.createElement('h3', {
        style: 'margin-top: 0; color: #d33;'
      }, ['Delete Item?']);
      modal.appendChild(title);

      const message = api.createElement('p', {}, [
        'Are you sure you want to delete "' + itemLabel + '"? This action cannot be undone.'
      ]);
      modal.appendChild(message);

      const buttonContainer = api.createElement('div', {
        style: 'display: flex; gap: 8px; justify-content: flex-end; margin-top: 20px;'
      }, []);

      const cancelBtn = api.createElement('button', {
        style: 'padding: 8px 16px; cursor: pointer; border: 1px solid #ccc; border-radius: 4px; background: white;',
        onclick: () => {
          document.body.removeChild(overlay);
        }
      }, ['Cancel']);
      buttonContainer.appendChild(cancelBtn);

      const confirmBtn = api.createElement('button', {
        style: 'padding: 8px 16px; cursor: pointer; background: #d33; color: white; border: none; border-radius: 4px;',
        onclick: async () => {
          document.body.removeChild(overlay);

          // Delete the item from database
          await api.delete(itemId);
          console.log('Deleted item:', itemId);

          // Remove references from all containers
          const allItems = await api.getAll();
          for (const item of allItems) {
            if (item.children && Array.isArray(item.children)) {
              const originalLength = item.children.length;

              // Filter out references (both simple IDs and positioned objects)
              item.children = item.children.filter(child => {
                const childId = typeof child === 'string' ? child : child.id;
                return childId !== itemId;
              });

              // Update if anything was removed
              if (item.children.length !== originalLength) {
                item.modified = Date.now();
                await api.set(item);
                console.log('Removed reference from:', item.id);
              }
            }
          }

          // If we deleted the current root, navigate to workspace
          if (itemId === rootId) {
            const WORKSPACE_ID = '00000000-0000-0000-0000-000000000006';
            await api.navigate(WORKSPACE_ID);
          } else {
            // Refresh current view
            await api.navigate(rootId);
          }
        }
      }, ['Delete']);
      buttonContainer.appendChild(confirmBtn);

      modal.appendChild(buttonContainer);
      overlay.appendChild(modal);

      // Close on overlay click
      overlay.onclick = (e) => {
        if (e.target === overlay) {
          document.body.removeChild(overlay);
        }
      };

      // Prevent modal close when clicking inside
      modal.onclick = (e) => {
        e.stopPropagation();
      };

      document.body.appendChild(overlay);
    };
    contextMenu.appendChild(deleteItem);

    // Position menu
    const menuWidth = 180;
    const menuHeight = 350;
    let menuX = x;
    let menuY = y;
    if (x + menuWidth > window.innerWidth) menuX = window.innerWidth - menuWidth - 10;
    if (y + menuHeight > window.innerHeight) menuY = window.innerHeight - menuHeight - 10;

    contextMenu.style.left = menuX + 'px';
    contextMenu.style.top = menuY + 'px';
    contextMenu.style.display = 'block';
  };

  // Helper: find the correct item element for selection, preferring nested context
  const findItemElement = (target) => {
    // First try to find an element with BOTH data-item-id AND data-parent-id
    // This identifies nested items in containers
    let element = target.closest('[data-parent-id][data-item-id]');

    // If not found, fall back to just data-item-id (for root items)
    if (!element) {
      element = target.closest('[data-item-id]');
    }

    return element;
  };

  // Event: click to select
  container.addEventListener('click', (e) => {
    // Close context menu on any click
    hideContextMenu();

    const itemElement = findItemElement(e.target);
    if (itemElement) {
      const itemId = itemElement.getAttribute('data-item-id');
      selectItem(itemId, itemElement);
      e.stopPropagation();
    } else {
      clearSelection();
    }
  });

  // Event: right-click for context menu
  container.addEventListener('contextmenu', (e) => {
    const itemElement = findItemElement(e.target);
    if (itemElement) {
      e.preventDefault();
      const itemId = itemElement.getAttribute('data-item-id');
      selectItem(itemId, itemElement);
      showContextMenu(e.clientX, e.clientY, itemId);
    }
  });

  // Event: Escape to clear selection or close menu
  container.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
      if (contextMenu.style.display !== 'none') {
        hideContextMenu();
      } else {
        clearSelection();
      }
    }
  });

  // Make container focusable for keyboard events
  container.setAttribute('tabindex', '0');

  return container;
}

export function render(value, onChange, api, options = {}) {
  const input = document.createElement('input');
  input.type = 'number';
  input.value = value ?? '';
  input.style.cssText = 'width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px;';

  if (options.min !== undefined) input.min = options.min;
  if (options.max !== undefined) input.max = options.max;
  if (options.step !== undefined) input.step = options.step;

  if (options.readonly) {
    input.readOnly = true;
    input.style.background = '#f5f5f5';
  }

  input.addEventListener('input', (e) => {
    const val = e.target.value === '' ? null : Number(e.target.value);
    onChange(val);
  });

  return input;
}

export function render(value, onChange, api, options = {}) {
  const select = document.createElement('select');
  select.style.cssText = 'width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px; background: white;';

  if (options.readonly) {
    select.disabled = true;
    select.style.background = '#f5f5f5';
  }

  // options.choices should be [{value, label}] or ['value1', 'value2']
  const choices = options.choices || [];

  for (const choice of choices) {
    const opt = document.createElement('option');
    if (typeof choice === 'object') {
      opt.value = choice.value;
      opt.textContent = choice.label || choice.value;
    } else {
      opt.value = choice;
      opt.textContent = choice;
    }
    if (opt.value === value) {
      opt.selected = true;
    }
    select.appendChild(opt);
  }

  select.addEventListener('change', (e) => {
    onChange(e.target.value);
  });

  return select;
}

/**
 * CSS Loader Library
 * Loads CSS items into the document head
 */

/**
 * Load a CSS item by name
 * @param {string} name - Name of the CSS item to load
 * @param {object} api - Hobson API
 * @returns {Promise<void>}
 */
export async function loadCSS(name, api) {
  const styleId = 'hobson-css-' + name;

  // Check if already loaded (idempotent)
  if (document.getElementById(styleId)) {
    return; // Already loaded
  }

  // Fetch CSS item by name
  const items = await api.query({ name });
  const cssItem = items.length > 0 ? items[0] : null;

  if (!cssItem) {
    throw new Error('CSS item not found: ' + name);
  }

  // Inject CSS into document head
  const styleTag = document.createElement('style');
  styleTag.id = styleId;
  styleTag.textContent = cssItem.content.code || '';
  document.head.appendChild(styleTag);

  console.log('Loaded CSS:', name);
}

/**
 * Unload a CSS item by name (useful for hot-reloading)
 * @param {string} name - Name of the CSS item to unload
 * @returns {boolean} - True if unloaded, false if not found
 */
export function unloadCSS(name) {
  const styleId = 'hobson-css-' + name;
  const styleTag = document.getElementById(styleId);

  if (styleTag) {
    styleTag.remove();
    console.log('Unloaded CSS:', name);
    return true;
  }

  return false;
}

/**
 * Reload a CSS item (unload + load)
 * @param {string} name - Name of the CSS item to reload
 * @param {object} api - Hobson API
 * @returns {Promise<void>}
 */
export async function reloadCSS(name, api) {
  unloadCSS(name);
  await loadCSS(name, api);
}

// Minimal marked.js implementation - just what we need
// Full library: https://cdn.jsdelivr.net/npm/marked@11.1.1/marked.min.js

const marked = (() => {
  const block = {
    newline: /^\n+/,
    code: /^( {4}[^\n]+\n*)+/,
    heading: /^ {0,3}(#{1,6})(?=\s|$)(.*)(?:\n+|$)/,
    hr: /^ {0,3}((?:- *){3,}|(?:_ *){3,}|(?:\* *){3,})(?:\n+|$)/,
    blockquote: /^( {0,3}> ?(>| )?(.*(?:\n(?! {0,3}\[)[^\n]+)*)(?:\n+|$))+/,
    list: /^( {0,3})(bull) [\s\S]+?(?:hr|def|\n{2,}(?! )(?!\1bull )\n*|\s*$)/,
    paragraph: /^([^\n]+(?:\n(?!hr|heading|blockquote)[^\n]+)*)/,
    text: /^[^\n]+/
  };

  const inline = {
    escape: /^\\([!"#$%&'()*+,\-./:;<=>?@\[\\\]^_`{|}~])/,
    link: /^!?\[((?:\[[^\]]*\]|[^\[\]]|\](?=[^\[]*\]))*)\]\(\s*<?(.*?)>?(?:\s+['"](.*?)['"])?\s*\)/,
    strong: /^__(.*?)__(?!_)|^\*\*(.*?)\*\*(?!\*)/,
    em: /^\b_((?:__|[^_])+?)_\b|^\*((?:\*\*|[^\*])+?)\*(?!\*)/,
    code: /^`([^`]|[^`][\s\S]*?[^`])`/,
    br: /^ {2,}\n(?!\s*$)/,
    text: /^[\s\S]+?(?=[\\<!\[_*`]| {2,}\n|$)/
  };

  function escape(html) {
    return html
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function parseInline(src) {
    let out = '';
    let cap;

    while (src) {
      // escape
      if (cap = inline.escape.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[1]);
        continue;
      }

      // link
      if (cap = inline.link.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1];
        const href = cap[2];
        out += '<a href="' + escape(href) + '">' + parseInline(text) + '</a>';
        continue;
      }

      // strong
      if (cap = inline.strong.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<strong>' + parseInline(cap[2] || cap[1]) + '</strong>';
        continue;
      }

      // em
      if (cap = inline.em.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<em>' + parseInline(cap[2] || cap[1]) + '</em>';
        continue;
      }

      // code
      if (cap = inline.code.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<code>' + escape(cap[1].trim()) + '</code>';
        continue;
      }

      // br
      if (cap = inline.br.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<br>';
        continue;
      }

      // text
      if (cap = inline.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += escape(cap[0]);
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  function parse(src) {
    let out = '';
    let cap;

    src = src.replace(/\r\n|\r/g, '\n').replace(/\t/g, '    ');

    while (src) {
      // newline
      if (cap = block.newline.exec(src)) {
        src = src.substring(cap[0].length);
        continue;
      }

      // code block
      if (cap = block.code.exec(src)) {
        src = src.substring(cap[0].length);
        const code = cap[0].replace(/^ {4}/gm, '');
        out += '<pre><code>' + escape(code.trim()) + '</code></pre>\n';
        continue;
      }

      // heading
      if (cap = block.heading.exec(src)) {
        src = src.substring(cap[0].length);
        const level = cap[1].length;
        const text = cap[2].trim();
        out += '<h' + level + '>' + parseInline(text) + '</h' + level + '>\n';
        continue;
      }

      // hr
      if (cap = block.hr.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<hr>\n';
        continue;
      }

      // blockquote
      if (cap = block.blockquote.exec(src)) {
        src = src.substring(cap[0].length);
        const quote = cap[0].replace(/^ *> ?/gm, '');
        out += '<blockquote>\n' + parse(quote) + '</blockquote>\n';
        continue;
      }

      // paragraph
      if (cap = block.paragraph.exec(src)) {
        src = src.substring(cap[0].length);
        const text = cap[1].trim();
        out += '<p>' + parseInline(text) + '</p>\n';
        continue;
      }

      // text (fallback)
      if (cap = block.text.exec(src)) {
        src = src.substring(cap[0].length);
        out += '<p>' + parseInline(cap[0]) + '</p>\n';
        continue;
      }

      if (src) {
        throw new Error('Infinite loop on byte: ' + src.charCodeAt(0));
      }
    }

    return out;
  }

  return { parse };
})();

export default marked;

